contracts/AvatarBase.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/// @title AvatarBase
/// @notice Stub seguro para registro imutavel de avatares na blockchain.
///         Cada avatar e um NFT ERC721 com CID IPFS do snapshot de memoria.
/// @dev Proximo passo: integrar AvatarWalletLink, ConsentRegistry e AvatarPro.
contract AvatarBase is ERC721, AccessControl, Pausable {
    bytes32 public constant MINTER_ROLE    = keccak256("MINTER_ROLE");
    bytes32 public constant UPDATER_ROLE   = keccak256("UPDATER_ROLE");
    bytes32 public constant DEACTIVATOR_ROLE = keccak256("DEACTIVATOR_ROLE");

    struct AvatarData {
        address creator;
        string  ipfsCID;
        uint64  creationTime;
        uint64  lastUpdateTime;
        bool    isActive;
    }

    uint256 private _nextAvatarId;

    mapping(uint256 => AvatarData)   private _avatarData;
    mapping(uint256 => string[])     private _snapshotHistory;

    event AvatarCreated(
        uint256 indexed avatarId,
        address indexed creator,
        string ipfsCID
    );
    event SnapshotUpdated(
        uint256 indexed avatarId,
        string newCID,
        address indexed operator
    );
    event AvatarDeactivated(
        uint256 indexed avatarId,
        address indexed operator
    );

    constructor(address admin) ERC721("SingulAI Avatar", "SGLA") {
        require(admin != address(0), "AVATAR: invalid admin");
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(MINTER_ROLE,        admin);
        _grantRole(UPDATER_ROLE,       admin);
        _grantRole(DEACTIVATOR_ROLE,   admin);
    }

    // ─── Operacoes de avatar ───────────────────────────────────────────────

    /// @notice Cria um avatar NFT para o criador com o CID do snapshot inicial.
    function mintAvatar(
        address creator,
        string calldata ipfsCID
    ) external whenNotPaused onlyRole(MINTER_ROLE) returns (uint256 avatarId) {
        require(creator != address(0), "AVATAR: invalid creator");
        require(bytes(ipfsCID).length > 0, "AVATAR: empty CID");

        avatarId = _nextAvatarId++;

        _avatarData[avatarId] = AvatarData({
            creator:        creator,
            ipfsCID:        ipfsCID,
            creationTime:   uint64(block.timestamp),
            lastUpdateTime: uint64(block.timestamp),
            isActive:       true
        });

        _snapshotHistory[avatarId].push(ipfsCID);
        _safeMint(creator, avatarId);

        emit AvatarCreated(avatarId, creator, ipfsCID);
    }

    /// @notice Atualiza o snapshot do avatar (novo CID IPFS com memorias adicionadas).
    ///         Pode ser chamado pelo proprio criador ou por UPDATER_ROLE.
    function updateSnapshot(
        uint256 avatarId,
        string calldata newCID
    ) external whenNotPaused {
        AvatarData storage data = _avatarData[avatarId];
        require(data.isActive, "AVATAR: avatar inactive");
        require(bytes(newCID).length > 0, "AVATAR: empty CID");
        require(
            data.creator == msg.sender || hasRole(UPDATER_ROLE, msg.sender),
            "AVATAR: not authorized"
        );

        data.ipfsCID        = newCID;
        data.lastUpdateTime = uint64(block.timestamp);
        _snapshotHistory[avatarId].push(newCID);

        emit SnapshotUpdated(avatarId, newCID, msg.sender);
    }

    /// @notice Desativa um avatar (direito ao esquecimento / LGPD).
    ///         Pode ser chamado pelo proprio criador ou por DEACTIVATOR_ROLE.
    function deactivateAvatar(uint256 avatarId) external whenNotPaused {
        AvatarData storage data = _avatarData[avatarId];
        require(data.isActive, "AVATAR: already inactive");
        require(
            data.creator == msg.sender || hasRole(DEACTIVATOR_ROLE, msg.sender),
            "AVATAR: not authorized"
        );

        data.isActive = false;

        emit AvatarDeactivated(avatarId, msg.sender);
    }

    // ─── Views ────────────────────────────────────────────────────────────

    function getAvatar(uint256 avatarId) external view returns (AvatarData memory) {
        return _avatarData[avatarId];
    }

    function getSnapshotHistory(uint256 avatarId) external view returns (string[] memory) {
        return _snapshotHistory[avatarId];
    }

    /// @dev Retorna URI IPFS do snapshot atual.
    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        _requireOwned(tokenId);
        return string.concat("ipfs://", _avatarData[tokenId].ipfsCID);
    }

    // ─── Hooks internos ──────────────────────────────────────────────────

    /// @dev Bloqueia transfers enquanto contrato estiver pausado.
    function _update(
        address to,
        uint256 tokenId,
        address auth
    ) internal override(ERC721) whenNotPaused returns (address) {
        return super._update(to, tokenId, auth);
    }

    // ─── Interface ────────────────────────────────────────────────────────

    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC721, AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }

    // ─── Admin ────────────────────────────────────────────────────────────

    function pause()   external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }
}

contracts/AvatarPro.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title AvatarPro
/// @notice Stub seguro para monetizacao de sessoes pagas em SGL.
///         Permite que avatares cobrem por sessoes de chat, voz e consultoria.
///         Audit trail on-chain com hash off-chain por sessao concluida.
/// @dev Proximo passo: integrar ConsentRegistry para bloquear sessoes sem consentimento
///      e AvatarWalletLink para controle granular de acesso.
contract AvatarPro is AccessControl, Pausable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    bytes32 public constant SESSION_MANAGER_ROLE = keccak256("SESSION_MANAGER_ROLE");
    bytes32 public constant PRICE_SETTER_ROLE    = keccak256("PRICE_SETTER_ROLE");

    struct ServiceConfig {
        uint256 pricePerSession;
        bool    isActive;
        uint32  maxSessionsPerDay;
    }

    struct Session {
        address user;
        uint256 avatarId;
        uint64  startTime;
        uint64  endTime;
        uint256 amountPaid;
        bytes32 sessionDataHash;  // hash do log off-chain para auditoria
    }

    IERC20  public immutable sglToken;
    address public treasury;
    uint256 public sessionCount;

    // avatarId => config de servico
    mapping(uint256 => ServiceConfig) public serviceConfigs;
    // sessionId => dados da sessao
    mapping(uint256 => Session) public sessions;
    // avatarId => usuario => dia (timestamp/86400) => contador
    mapping(uint256 => mapping(address => mapping(uint256 => uint256))) private _dailyCount;

    event ServiceConfigured(
        uint256 indexed avatarId,
        uint256 pricePerSession,
        bool isActive,
        uint32 maxSessionsPerDay
    );
    event SessionRequested(
        uint256 indexed sessionId,
        uint256 indexed avatarId,
        address indexed user,
        uint256 amountPaid
    );
    event SessionFinalized(
        uint256 indexed sessionId,
        bytes32 sessionDataHash,
        address indexed operator
    );
    event TreasuryUpdated(
        address indexed oldTreasury,
        address indexed newTreasury
    );

    constructor(
        address tokenAddress,
        address treasuryAddress,
        address admin
    ) {
        require(tokenAddress    != address(0), "PRO: invalid token");
        require(treasuryAddress != address(0), "PRO: invalid treasury");
        require(admin           != address(0), "PRO: invalid admin");

        sglToken = IERC20(tokenAddress);
        treasury = treasuryAddress;

        _grantRole(DEFAULT_ADMIN_ROLE,   admin);
        _grantRole(SESSION_MANAGER_ROLE, admin);
        _grantRole(PRICE_SETTER_ROLE,    admin);
    }

    // ─── Configuracao de servico ──────────────────────────────────────────

    /// @notice Define preco, status e limite diario de sessoes de um avatar.
    function configureService(
        uint256 avatarId,
        uint256 pricePerSession,
        bool    isActive,
        uint32  maxSessionsPerDay
    ) external onlyRole(PRICE_SETTER_ROLE) {
        require(maxSessionsPerDay > 0, "PRO: invalid daily limit");

        serviceConfigs[avatarId] = ServiceConfig({
            pricePerSession:  pricePerSession,
            isActive:         isActive,
            maxSessionsPerDay: maxSessionsPerDay
        });

        emit ServiceConfigured(avatarId, pricePerSession, isActive, maxSessionsPerDay);
    }

    // ─── Sessoes ───────────────────────────────────────────────────────────

    /// @notice Inicia uma sessao paga com o avatar.
    ///         Debita SGL do usuario diretamente para o treasury.
    function requestSession(
        uint256 avatarId
    ) external whenNotPaused nonReentrant returns (uint256 sessionId) {
        ServiceConfig storage config = serviceConfigs[avatarId];
        require(config.isActive, "PRO: service inactive");
        require(config.maxSessionsPerDay > 0, "PRO: service not configured");

        uint256 today = block.timestamp / 1 days;
        require(
            _dailyCount[avatarId][msg.sender][today] < config.maxSessionsPerDay,
            "PRO: daily session limit reached"
        );

        sessionId = sessionCount++;

        sessions[sessionId] = Session({
            user:            msg.sender,
            avatarId:        avatarId,
            startTime:       uint64(block.timestamp),
            endTime:         0,
            amountPaid:      config.pricePerSession,
            sessionDataHash: bytes32(0)
        });

        _dailyCount[avatarId][msg.sender][today]++;

        if (config.pricePerSession > 0) {
            sglToken.safeTransferFrom(msg.sender, treasury, config.pricePerSession);
        }

        emit SessionRequested(sessionId, avatarId, msg.sender, config.pricePerSession);
    }

    /// @notice Finaliza uma sessao registrando o hash do log de interacao off-chain.
    ///         Prova auditavel imutavel de que a sessao ocorreu.
    function finalizeSession(
        uint256 sessionId,
        bytes32 sessionDataHash
    ) external onlyRole(SESSION_MANAGER_ROLE) {
        Session storage session = sessions[sessionId];
        require(session.startTime > 0, "PRO: session not found");
        require(session.endTime == 0,  "PRO: already finalized");
        require(sessionDataHash != bytes32(0), "PRO: invalid hash");

        session.endTime         = uint64(block.timestamp);
        session.sessionDataHash = sessionDataHash;

        emit SessionFinalized(sessionId, sessionDataHash, msg.sender);
    }

    // ─── Views ────────────────────────────────────────────────────────────

    function getDailyCount(
        uint256 avatarId,
        address user
    ) external view returns (uint256) {
        return _dailyCount[avatarId][user][block.timestamp / 1 days];
    }

    // ─── Admin ────────────────────────────────────────────────────────────

    function setTreasury(address newTreasury) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newTreasury != address(0), "PRO: invalid treasury");
        emit TreasuryUpdated(treasury, newTreasury);
        treasury = newTreasury;
    }

    function pause()   external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }
}

