// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/// @title AvatarWalletLink
/// @notice Stub seguro para vincular carteiras a avatares com niveis de permissao.
///         Todas as concessoes e revogacoes ficam registradas como eventos on-chain
///         para trilha de auditoria (LGPD/GDPR).
/// @dev Proximo passo: integrar validacao de titularidade via AvatarBase NFT.
contract AvatarWalletLink is AccessControl, Pausable {
    bytes32 public constant LINKER_ROLE = keccak256("LINKER_ROLE");

    /// @notice Niveis de permissao crescentes por carteira vinculada.
    enum PermissionLevel {
        None,        // sem vinculo
        Viewer,      // so pode visualizar o avatar publico
        Interactor,  // pode iniciar sessoes de chat/voz
        Manager      // pode atualizar snapshots e delegar permissoes
    }

    struct WalletPermission {
        PermissionLevel level;
        uint64 grantedAt;
        uint64 expiresAt;   // 0 = sem expiracao
    }

    // avatarId => carteira => permissao
    mapping(uint256 => mapping(address => WalletPermission)) private _permissions;
    // avatarId => lista de carteiras vinculadas (nao removidas para manter rastro)
    mapping(uint256 => address[]) private _linkedWallets;

    event WalletLinked(
        uint256 indexed avatarId,
        address indexed wallet,
        PermissionLevel level,
        uint64 expiresAt
    );
    event WalletUnlinked(
        uint256 indexed avatarId,
        address indexed wallet,
        address indexed operator
    );
    event PermissionUpdated(
        uint256 indexed avatarId,
        address indexed wallet,
        PermissionLevel oldLevel,
        PermissionLevel newLevel
    );

    constructor(address admin) {
        require(admin != address(0), "LINK: invalid admin");
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(LINKER_ROLE, admin);
    }

    // ─── Vinculacao ───────────────────────────────────────────────────────

    /// @notice Vincula uma carteira a um avatar com nivel de permissao e expiracao opcional.
    function linkWallet(
        uint256 avatarId,
        address wallet,
        PermissionLevel level,
        uint64 expiresAt
    ) external whenNotPaused onlyRole(LINKER_ROLE) {
        require(wallet != address(0), "LINK: invalid wallet");
        require(level != PermissionLevel.None, "LINK: invalid level");
        require(expiresAt == 0 || expiresAt > block.timestamp, "LINK: invalid expiry");

        WalletPermission storage perm = _permissions[avatarId][wallet];
        bool isNew = perm.level == PermissionLevel.None;

        if (!isNew) {
            emit PermissionUpdated(avatarId, wallet, perm.level, level);
        }

        perm.level     = level;
        perm.grantedAt = uint64(block.timestamp);
        perm.expiresAt = expiresAt;

        if (isNew) {
            _linkedWallets[avatarId].push(wallet);
            emit WalletLinked(avatarId, wallet, level, expiresAt);
        }
    }

    /// @notice Remove o vinculo de uma carteira com um avatar.
    ///         O evento permanece no historico on-chain para auditoria.
    function unlinkWallet(
        uint256 avatarId,
        address wallet
    ) external whenNotPaused onlyRole(LINKER_ROLE) {
        require(
            _permissions[avatarId][wallet].level != PermissionLevel.None,
            "LINK: not linked"
        );

        delete _permissions[avatarId][wallet];

        emit WalletUnlinked(avatarId, wallet, msg.sender);
    }

    // ─── Views ────────────────────────────────────────────────────────────

    /// @notice Verifica se uma carteira possui pelo menos o nivel de permissao requerido
    ///         e se o vinculo nao expirou.
    function hasPermission(
        uint256 avatarId,
        address wallet,
        PermissionLevel minLevel
    ) external view returns (bool) {
        WalletPermission storage perm = _permissions[avatarId][wallet];
        if (perm.level < minLevel) return false;
        if (perm.expiresAt != 0 && block.timestamp > perm.expiresAt) return false;
        return true;
    }

    /// @notice Retorna o registro completo de permissao de uma carteira.
    function getPermission(
        uint256 avatarId,
        address wallet
    ) external view returns (WalletPermission memory) {
        return _permissions[avatarId][wallet];
    }

    /// @notice Lista todas as carteiras que ja foram vinculadas a um avatar.
    ///         Inclui registros deletados (nivel None) para preservar trilha historica.
    function getLinkedWallets(uint256 avatarId) external view returns (address[] memory) {
        return _linkedWallets[avatarId];
    }

    // ─── Admin ────────────────────────────────────────────────────────────

    function pause()   external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }
}

contracts/ConsentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/// @title ConsentRegistry
/// @notice Stub seguro para registro de consentimentos LGPD/GDPR on-chain.
///         Usa bitmask para combinar multiplos tipos de consentimento em um unico registro.
///         Toda concessao e revogacao gera evento imutavel para trilha de prova legal.
/// @dev Proximo passo: integrar com pipeline off-chain para remoção de dados (direito
///      ao esquecimento) e com AvatarPro para bloquear sessoes sem consentimento.
contract ConsentRegistry is AccessControl, Pausable {
    bytes32 public constant CONSENT_MANAGER_ROLE = keccak256("CONSENT_MANAGER_ROLE");

    // ─── Tipos de consentimento (bitmask) ─────────────────────────────────
    uint8 public constant CONSENT_VOICE      = 1;  // bit 0 - uso de voz/audio
    uint8 public constant CONSENT_MARKETING  = 2;  // bit 1 - comunicacoes marketing
    uint8 public constant CONSENT_DATA_SALE  = 4;  // bit 2 - venda de interacoes
    uint8 public constant CONSENT_LEGAL_USE  = 8;  // bit 3 - uso em contextos juridicos

    struct ConsentRecord {
        uint8   grantedFlags;    // bitmask dos consentimentos vigentes
        uint64  lastUpdatedAt;
        bytes32 documentHash;    // hash do documento de consentimento assinado
    }

    // avatarId => usuario => registro de consentimento
    mapping(uint256 => mapping(address => ConsentRecord)) private _consents;

    event ConsentGranted(
        uint256 indexed avatarId,
        address indexed user,
        uint8 flags,
        bytes32 documentHash
    );
    event ConsentRevoked(
        uint256 indexed avatarId,
        address indexed user,
        uint8 revokedFlags,
        uint8 remainingFlags
    );

    constructor(address admin) {
        require(admin != address(0), "CONSENT: invalid admin");
        _grantRole(DEFAULT_ADMIN_ROLE,   admin);
        _grantRole(CONSENT_MANAGER_ROLE, admin);
    }

    // ─── Gestao de consentimento ──────────────────────────────────────────

    /// @notice Registra consentimentos concedidos pelo usuario.
    ///         Acumula flags: chamar novamente adiciona novas permissoes sem remover existentes.
    /// @param avatarId     ID do avatar ao qual o consentimento se aplica.
    /// @param user         Endereço do usuario que consentiu.
    /// @param flags        Bitmask das permissoes concedidas (ex: CONSENT_VOICE | CONSENT_MARKETING).
    /// @param documentHash Hash SHA-256 do documento de consentimento assinado (LGPD Art. 8).
    function grantConsent(
        uint256 avatarId,
        address user,
        uint8   flags,
        bytes32 documentHash
    ) external whenNotPaused onlyRole(CONSENT_MANAGER_ROLE) {
        require(user         != address(0), "CONSENT: invalid user");
        require(flags        >  0,          "CONSENT: no flags set");
        require(documentHash != bytes32(0), "CONSENT: invalid document hash");

        ConsentRecord storage record = _consents[avatarId][user];
        record.grantedFlags   |= flags;
        record.lastUpdatedAt   = uint64(block.timestamp);
        record.documentHash    = documentHash;

        emit ConsentGranted(avatarId, user, flags, documentHash);
    }

    /// @notice Revoga consentimentos especificos do usuario (direito de retirada LGPD Art. 8 §5).
    ///         O evento permanece on-chain como prova da revogacao.
    /// @param flags Bitmask dos consentimentos a serem revogados.
    function revokeConsent(
        uint256 avatarId,
        address user,
        uint8   flags
    ) external whenNotPaused onlyRole(CONSENT_MANAGER_ROLE) {
        require(user  != address(0), "CONSENT: invalid user");
        require(flags >  0,          "CONSENT: no flags set");

        ConsentRecord storage record = _consents[avatarId][user];
        require(
            (record.grantedFlags & flags) != 0,
            "CONSENT: flags not previously granted"
        );

        record.grantedFlags  &= ~flags;
        record.lastUpdatedAt  = uint64(block.timestamp);

        emit ConsentRevoked(avatarId, user, flags, record.grantedFlags);
    }

    // ─── Views ────────────────────────────────────────────────────────────

    /// @notice Verifica se o usuario possui TODOS os consentimentos solicitados vigentes.
    function hasConsent(
        uint256 avatarId,
        address user,
        uint8   flags
    ) external view returns (bool) {
        return ((_consents[avatarId][user].grantedFlags & flags) == flags);
    }

    /// @notice Retorna o registro completo de consentimento de um usuario.
    function getConsent(
        uint256 avatarId,
        address user
    ) external view returns (ConsentRecord memory) {
        return _consents[avatarId][user];
    }

    // ─── Admin ────────────────────────────────────────────────────────────

    function pause()   external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }
}

